  "disappeared": [{"concept": "titolo breve", "who": ["Nome Persona"], "detail": "spiegazione in 1 frase"}],
  "evolved": [{"concept": "titolo breve", "from": "come era prima", "to": "come è ora", "who": ["Nome Persona"]}],
